const inputItems = $input.all();
const out = [];

const ALLOWED_EXTENSIONS = [
  'pdf',
  'jpg',
  'jpeg',
  'png',
  'gif',
  'tif',
  'tiff',
  'doc',
  'docx',
  'xls',
  'xlsx',
  'ppt',
  'pptx',
  'odt',
  'ods',
  'zip'
];

function sanitizeFilePart(str, maxLen = 90) {
  return String(str || '')
    .replace(/[\/\\:*?"<>|\r\n]/g, '_')
    .replace(/\s+/g, '_')
    .replace(/_+/g, '_')
    .replace(/^_+|_+$/g, '')
    .substring(0, maxLen);
}

function getExtensionFromText(str) {
  const clean = String(str || '').split('?')[0].split('#')[0];
  const m = clean.match(/\.([a-zA-Z0-9]{2,6})$/);
  if (!m) return '';

  const ext = m[1].toLowerCase();
  return ALLOWED_EXTENSIONS.includes(ext) ? ext : '';
}

function getExtension(doc) {
  const candidates = [
    doc.url || '',
    doc.label || '',
    doc.docKey || ''
  ];

  for (const c of candidates) {
    const ext = getExtensionFromText(c);
    if (ext) return ext;
  }

  const url = String(doc.url || '').toLowerCase();

  if (url.includes('do027.asp') || url.includes('dolfdnr=')) {
    return 'pdf';
  }

  return 'bin';
}

function isUploadCandidate(doc) {
  const url = String(doc.url || '').toLowerCase();

  if (!url) return false;

  if (url.includes('/stadt/politik/allris/do027.asp')) return true;
  if (url.includes('dolfdnr=')) return true;

  if (url.includes('/stadt/politik/allris/___tmp/tmp/')) return true;
  if (url.includes('/allris/___tmp/tmp/')) return true;

  const ext = getExtension(doc);
  if (ext && ext !== 'bin') return true;

  return false;
}

for (const item of inputItems) {
  const j = item.json || {};

  let docs = [];
  try {
    docs = JSON.parse(j.documentsJson || '[]');
    if (!Array.isArray(docs)) docs = [];
  } catch (e) {
    console.warn(`[Expand] documentsJson konnte nicht gelesen werden für ${j.vorgangKey}: ${e.message}`);
    docs = [];
  }

  const uploadDocs = [];
  const skippedDocs = [];

  for (let i = 0; i < docs.length; i++) {
    const doc = docs[i] || {};

    if (isUploadCandidate(doc)) {
      uploadDocs.push({
        ...doc,
        _sourceDocIndex: i + 1
      });
    } else {
      skippedDocs.push({
        url: doc.url || '',
        type: doc.type || '',
        label: doc.label || '',
        docKey: doc.docKey || '',
        reason: 'kein echter Datei-/ALLRIS-Downloadlink'
      });
    }
  }

  console.log(
    `[Expand] ${j.vorgangKey}: ${docs.length} Links gesamt, ` +
    `${uploadDocs.length} Upload-Kandidaten, ${skippedDocs.length} übersprungen.`
  );

  let uploadIndex = 0;

  for (const doc of uploadDocs) {
    uploadIndex++;

    const url = doc.url || '';
    const dolfdnr = url.match(/DOLFDNR=(\d+)/i)?.[1];

    const ext = getExtension(doc);
    const paddedIdx = String(uploadIndex).padStart(2, '0');

    const docType = doc.type || 'document';
    let suffix = 'dokument';

    if (docType === 'original') suffix = 'original';
    if (docType === 'anlage') suffix = 'anlage';

    let cleanDocKey = sanitizeFilePart(doc.docKey || '', 100)
      .replace(/^anlage_/, '')
      .replace(/^original_/, '')
      .replace(/^document_/, '')
      .replace(/\.[a-zA-Z0-9]{2,6}$/, '');

    let nc_fileName;

    if (dolfdnr) {
      nc_fileName = `dol_${dolfdnr}.pdf`;
    } else if (cleanDocKey) {
      nc_fileName = `${paddedIdx}_${suffix}_${cleanDocKey}.${ext}`;
    } else {
      nc_fileName = `${paddedIdx}_${suffix}.${ext}`;
    }

    out.push({
      json: {
        ...j,

        // Wichtig: für die spätere Aggregation nur echte Uploads zählen
        documentCount: uploadDocs.length,

        _sourceDocumentCount: docs.length,
        _skippedDocumentCount: skippedDocs.length,
        _skippedDocumentsJson: JSON.stringify(skippedDocs),

        url,
        type: docType,
        label: doc.label || '',
        docKey: doc.docKey || '',
        _sourceDocIndex: doc._sourceDocIndex || uploadIndex,

        referer:
          j.allrisUrl ||
          j.sourceUrl ||
          'https://www.goslar.de/stadt/politik/allris/vo040_r.asp',

        nc_fileName,
        nc_docIndex: uploadIndex,
        docRunKey: `${j.vorgangKey}::${uploadIndex}::${url}`,

        _forceRefreshDocuments: j._forceRefreshDocuments === true,
        _forceRefreshOnlyVorgangKey: j._forceRefreshOnlyVorgangKey || '',
        _deleteExistingBeforeUpload: j._deleteExistingBeforeUpload === true,
        _existingNextcloudFolder: j._existingNextcloudFolder || ''
      }
    });
  }
}

return out;

// Bereinigt einen Ordnerpfad-Wert aus der DataTable.
// Erkennt String-"null", "undefined", "-" als leere Werte.
function sanitizeFolder(raw) {
  const s = (raw || '').trim();
  if (s.toLowerCase() === 'null' ||
      s.toLowerCase() === 'undefined' ||
      s === '-') {
    return '';
  }
  return s;
}

// Baut den Nextcloud-Ordnerpfad aus Vorgangsnummer + Titel.
// Bei Force-Refresh wird der bestehende Ordner wiederverwendet,
// damit kein neuer Ordner bei geänderten Titeln entsteht.
// existingFolder wird robust bereinigt – "null"-Strings führen nicht zu falschen Pfaden.

const j = $input.item.json;

function sanitize(str, maxLen) {
  return (str || '')
    .replace(/[\/\\:*?"<>|\r\n]/g, '_')
    .replace(/\s+/g, '_')
    .replace(/_+/g, '_')
    .replace(/^_+|_+$/g, '')
    .substring(0, maxLen || 50);
}

// ── Force-Refresh: bestehenden Ordner weiterverwenden ─────────────────────
const forceRefresh   = j._forceRefreshDocuments === true;
// Robust bereinigen: "null", "undefined", "-" → leerer String
const existingFolder = sanitizeFolder(j._existingNextcloudFolder);

let nc_pathYear, nc_pathVorg, nc_pathOrig, nc_folder, nc_year;

if (forceRefresh && existingFolder) {
  // Bestehenden Pfad übernehmen
  nc_pathVorg = existingFolder;
  nc_pathOrig = existingFolder + '/01_originale';

  // nc_pathYear aus existingFolder ableiten
  // Schema: /DiePARTEI/Allris/<Jahr>/<Ordner> → Segmente nach split('/')
  const parts = existingFolder.split('/').filter(Boolean);
  if (parts.length >= 3) {
    nc_year     = parts[2] || new Date().getFullYear().toString();
    nc_pathYear = '/' + parts.slice(0, 3).join('/');
    nc_folder   = parts.slice(3).join('/') || sanitize(`${(j.vorgangKey||'').replace(/\//g,'_')}_${j.title||''}`, 120);
  } else {
    nc_year     = new Date().getFullYear().toString();
    nc_pathYear = `/DiePARTEI/Allris/${nc_year}`;
    nc_folder   = sanitize(`${(j.vorgangKey||'').replace(/\//g,'_')}_${j.title||''}`, 120);
    console.warn(`[BuildPath] Force-Refresh: Pfad-Schema unklar für "${existingFolder}", nutze Fallback.`);
  }
  console.log(`[BuildPath] Force-Refresh: verwende bestehenden Ordner "${nc_pathVorg}"`);
} else {
  // Normalbetrieb (oder Force-Refresh ohne gültigen bestehenden Ordner):
  // neuen Pfad bauen
  if (forceRefresh && !existingFolder) {
    console.log('[BuildPath] Force-Refresh: kein gültiger existingFolder, baue neuen Pfad.');
  }
  nc_year     = new Date().getFullYear().toString();
  const vgnr  = (j.vorgangKey || 'unbekannt').replace(/\//g, '_');
  const title = sanitize(j.title || '', 80);
  nc_folder   = sanitize(`${vgnr}_${title}`, 120);
  nc_pathYear = `/DiePARTEI/Allris/${nc_year}`;
  nc_pathVorg = `/DiePARTEI/Allris/${nc_year}/${nc_folder}`;
  nc_pathOrig = `/DiePARTEI/Allris/${nc_year}/${nc_folder}/01_originale`;
}

// Sicherheitscheck: nc_pathVorg darf niemals "null" oder leer sein
if (!nc_pathVorg || nc_pathVorg === 'null' || nc_pathVorg.startsWith('null')) {
  throw new Error(
    `[BuildPath] KRITISCH: nc_pathVorg ist ungültig ("${nc_pathVorg}") ` +
    `für Vorgang ${j.vorgangKey||'?'}. existingFolder war: "${j._existingNextcloudFolder}"`
  );
}

return [{
  json: {
    ...j,
    nc_year,
    nc_folder,
    nc_pathYear,
    nc_pathVorg,
    nc_pathOrig
  }
}];

// Bereinigt einen Ordnerpfad-Wert aus der DataTable.
// Erkennt String-"null", "undefined", "-" als leere Werte.
function sanitizeFolder(raw) {
  const s = (raw || '').trim();
  if (s.toLowerCase() === 'null' ||
      s.toLowerCase() === 'undefined' ||
      s === '-') {
    return '';
  }
  return s;
}

// Filtert DataTable-Zeilen und wertet Force-Refresh-Konfiguration aus.

// ── Konfiguration lesen ───────────────────────────────────────────────────
const cfg = $('Archiv Konfiguration').first()?.json || {};
const forceRefreshDocuments      = cfg.forceRefreshDocuments      === true;
const forceRefreshOnlyVorgangKey = (cfg.forceRefreshOnlyVorgangKey || '').trim();
const forceRefreshAllConfirmed   = cfg.forceRefreshAllConfirmed   === true;
const deleteExistingBeforeUpload = cfg.deleteExistingBeforeUpload === true;

// ── Sicherheitsbremse ─────────────────────────────────────────────────────
if (forceRefreshDocuments && !forceRefreshOnlyVorgangKey && !forceRefreshAllConfirmed) {
  throw new Error(
    '[Filter] ABBRUCH: forceRefreshDocuments ist true, aber weder ' +
    'forceRefreshOnlyVorgangKey noch forceRefreshAllConfirmed ist gesetzt. ' +
    'Bitte in "Archiv Konfiguration" einen dieser Schalter setzen.'
  );
}

if (forceRefreshDocuments) {
  console.log(
    forceRefreshOnlyVorgangKey
      ? `[Filter] Force-Refresh-Modus: nur Vorgang "${forceRefreshOnlyVorgangKey}"`
      : `[Filter] Force-Refresh-Modus: ALLE Vorgänge (forceRefreshAllConfirmed=true)`
  );
}

// ── Filterlogik ───────────────────────────────────────────────────────────
const out = [];

for (const item of items) {
  const j = item.json;

  // Filter 1: documentCount muss > 0 sein
  const docCount = parseInt(j.documentCount || '0', 10);
  if (docCount === 0) continue;

  // Filter 2: documentsJson muss gültiges nicht-leeres Array sein
  let docs = [];
  try {
    docs = JSON.parse(j.documentsJson || '[]');
  } catch (e) {
    docs = [];
  }
  if (!Array.isArray(docs) || docs.length === 0) continue;

  // Filter 3: nextcloudFolder robust bereinigen (String-"null" etc. als leer werten)
  const folder = sanitizeFolder(j.nextcloudFolder);

  if (!forceRefreshDocuments) {
    // Normalbetrieb: nur Vorgänge ohne nextcloudFolder
    if (folder.length > 0) continue;
    // Nach 3 gescheiterten Versuchen endgültig aufgeben - kein weiterer Retry mehr,
    // außer über den Force-Refresh-Schalter.
    if (j.status === 'nextcloud_failed_final') continue;
  } else {
    // Force-Modus: nur den angegebenen Vorgang wenn forceRefreshOnlyVorgangKey gesetzt
    if (forceRefreshOnlyVorgangKey) {
      if (j.vorgangKey !== forceRefreshOnlyVorgangKey) continue;
    }
    // sonst: alle Vorgänge durchlassen (forceRefreshAllConfirmed = true)
  }

  out.push({
    json: {
      ...j,
      _forceRefreshDocuments:      forceRefreshDocuments,
      _forceRefreshOnlyVorgangKey: forceRefreshOnlyVorgangKey,
      _deleteExistingBeforeUpload: deleteExistingBeforeUpload,
      _existingNextcloudFolder:    folder   // bereinigter Wert, niemals "null"
    }
  });
}

// Vorgänge von alt nach neu sortieren
out.sort((a, b) => {
  const aDate = Date.parse(a.json.firstseen || a.json.createdAt || '') || 0;
  const bDate = Date.parse(b.json.firstseen || b.json.createdAt || '') || 0;

  if (aDate !== bDate) {
    return aDate - bDate; // alt → neu
  }

  const aVol = parseInt(a.json.volfdnr || '0', 10);
  const bVol = parseInt(b.json.volfdnr || '0', 10);

  return aVol - bVol;
});

console.log(`[Filter] ${out.length} Vorgänge zum Verarbeiten (aus ${items.length} DataTable-Zeilen).`);
return out;

// Stellt JSON-Metadaten nach dem HTTP-Download wieder her.
// Läuft im Modus "Run Once for Each Item" – verarbeitet ein Item pro Aufruf.
// Primär: item.json (HTTP-Node gibt bei responseFormat=file das JSON durch).
// Sekundär: Suche in Expand Documents anhand des docRunKey.

const item = $input.item;
const j    = item.json;

const docRunKey    = j.docRunKey || '';
const hasFullMeta  = !!(j.vorgangKey && j.nc_fileName && j.nc_pathOrig);

let meta = {};
if (!hasFullMeta && docRunKey) {
  const src   = $('Expand Documents').all();
  const found = src.find(i => i.json.docRunKey === docRunKey);
  if (found) {
    meta = found.json;
    console.log(`[RestoreMeta] Metadaten via docRunKey: ${docRunKey}`);
  } else {
    console.warn(`[RestoreMeta] WARNUNG: docRunKey '${docRunKey}' nicht in Expand Documents!`);
  }
} else if (!hasFullMeta) {
  console.warn('[RestoreMeta] WARNUNG: Keine Metadaten und kein docRunKey.');
}

const httpStatus = j.statusCode || j._httpStatus || '';

return {
  json: {
    vorgangKey:     j.vorgangKey     || meta.vorgangKey     || '',
    volfdnr:        j.volfdnr        || meta.volfdnr        || '',
    title:          j.title          || meta.title          || '',
    vorgangsnummer: j.vorgangsnummer || meta.vorgangsnummer || '',
    allrisUrl:      j.allrisUrl      || meta.allrisUrl      || '',
    sourceUrl:      j.sourceUrl      || meta.sourceUrl      || '',
    documentCount:  j.documentCount  || meta.documentCount  || 0,
    documentsJson:  j.documentsJson  || meta.documentsJson  || '[]',
    referer:        j.referer        || meta.referer        || '',
    url:            j.url            || meta.url            || '',
    type:           j.type           || meta.type           || '',
    nc_pathYear:    j.nc_pathYear    || meta.nc_pathYear    || '',
    nc_pathVorg:    j.nc_pathVorg    || meta.nc_pathVorg    || '',
    nc_pathOrig:    j.nc_pathOrig    || meta.nc_pathOrig    || '',
    nc_folder:      j.nc_folder      || meta.nc_folder      || '',
    nc_fileName:    j.nc_fileName    || meta.nc_fileName    || '',
    nc_docIndex:    j.nc_docIndex    ?? meta.nc_docIndex    ?? 0,
    docRunKey:      j.docRunKey      || meta.docRunKey      || '',
    // Force-Refresh-Felder erhalten (aus item.json oder meta)
    _forceRefreshDocuments:      j._forceRefreshDocuments      ?? meta._forceRefreshDocuments      ?? false,
    _forceRefreshOnlyVorgangKey: j._forceRefreshOnlyVorgangKey || meta._forceRefreshOnlyVorgangKey || '',
    _deleteExistingBeforeUpload: j._deleteExistingBeforeUpload ?? meta._deleteExistingBeforeUpload ?? false,
    _existingNextcloudFolder:    j._existingNextcloudFolder    || meta._existingNextcloudFolder    || '',
    _httpStatus:    httpStatus,
    _downloadOk:    !j.error && !!(item.binary?.data)
  },
  binary: item.binary || {}
};

// Aggregiert Upload-Ergebnisse je Vorgang.
// Input kommt aus dem nativen Merge-Node (mode: append).
//
// n8n Merge-Node (append): Feuert sobald EINER der Inputs Daten liefert
// und der andere Input ebenfalls gefeuert hat oder leer ist.
// Bei batchSize:1 pro Vorgang und Dokument-Loop:
//   - Alle erfolgreichen Uploads kommen über Markiere Upload Erfolg → Merge input0
//   - Alle Fehler kommen über Markiere Upload Fehler → Merge input1
//   - Wenn ALLE Dokumente erfolgreich: input1 empfängt keine Items → Merge
//     gibt trotzdem alle input0-Items weiter (append-Modus)
//   - Wenn KEIN Dokument erfolgreich: input0 empfängt keine Items → Merge
//     gibt trotzdem alle input1-Items weiter
// → Alle 4 Fälle werden korrekt behandelt:
//   (a) alle OK          → nur input0-Items
//   (b) ein Downloadfehler → input0 (Erfolge) + input1 (der Fehler)
//   (c) ein Uploadfehler   → input0 (Erfolge) + input1 (der Fehler)
//   (d) nur Fehler          → nur input1-Items

const allItems = $input.all();
const groups   = {};

if (allItems.length === 0) {
  console.warn('[Aggregation] WARNUNG: Keine Items empfangen – Merge-Node hat nichts geliefert.');
  return [];
}

for (const item of allItems) {
  const j   = item.json;
  const key = j.vorgangKey || '_unbekannt_';

  if (!groups[key]) {
    groups[key] = {
      vorgangKey:    j.vorgangKey,
      title:         j.title          || '',
      nc_pathVorg:   j.nc_pathVorg    || '',
      nc_pathOrig:   j.nc_pathOrig    || '',
      nc_pathYear:   j.nc_pathYear    || '',
      documentCount: parseInt(j.documentCount || '0', 10),
      allrisUrl:     j.allrisUrl      || '',
      sourceUrl:     j.sourceUrl      || '',
      documentsJson: j.documentsJson  || '[]',
      firstseen:     j.firstseen      || '',
      nextcloudRetryCount: parseInt(j.nextcloudRetryCount || '0', 10),
      uploaded:      0,
      failed:        0,
      errors:        []
    };
  }

  if (j._uploadOk === true) {
    groups[key].uploaded++;
  } else {
    groups[key].failed++;
    const errMsg = j._uploadError
      || `Dokument ${j.nc_docIndex ?? '?'} (${j.nc_fileName || '?'}) fehlgeschlagen`;
    groups[key].errors.push(errMsg);
  }
}

return Object.values(groups).map(g => {
  const expected = g.documentCount;
  // Streng: alle erwarteten Dokumente müssen erfolgreich hochgeladen sein
  const allOk    = g.failed === 0 && g.uploaded === expected && expected > 0;

  if (allOk) {
    console.log(`[Aggregation] ✓ Vorgang ${g.vorgangKey}: alle ${expected} Dokumente hochgeladen`);
  } else {
    console.warn(
      `[Aggregation] ✗ Vorgang ${g.vorgangKey}: ` +
      `erwartet=${expected}, hochgeladen=${g.uploaded}, fehlgeschlagen=${g.failed}`
    );
  }

  const maxRetries    = 3;
  const newRetryCount = allOk ? g.nextcloudRetryCount : g.nextcloudRetryCount + 1;
  const giveUp        = !allOk && newRetryCount >= maxRetries;

  if (giveUp) {
    console.warn(`[Aggregation] ⛔ Vorgang ${g.vorgangKey}: endgültig aufgegeben nach ${newRetryCount} Versuchen.`);
  }

  return {
    json: {
      vorgangKey:      g.vorgangKey,
      title:           g.title,
      allrisUrl:       g.allrisUrl,
      sourceUrl:       g.sourceUrl,
      documentsJson:   g.documentsJson,
      nc_pathVorg:     g.nc_pathVorg,
      nc_pathOrig:     g.nc_pathOrig,
      nc_pathYear:     g.nc_pathYear,
      documentCount:   g.documentCount,
      firstseen:       g.firstseen,
      _expectedCount:  expected,
      _uploadedCount:  g.uploaded,
      _failedCount:    g.failed,
      _uploadErrors:   g.errors,
      _allUploadsOk:   allOk,
      nextcloudFolder: allOk ? g.nc_pathVorg : '',
      nextcloudRetryCount: newRetryCount,
      status:          allOk ? 'nextcloud_archived' : (giveUp ? 'nextcloud_failed_final' : 'nextcloud_failed')
    }
  };
});

// Stellt die Vorgang-Metadaten nach dem Warmup-Request wieder her.
// Metadaten kommen aus 'Restore nach Ordneranlage'.
// Bei batchSize:1 ist idx immer 0; ?? 0 als sicherer Fallback.

const item   = $input.item;
const warmup = item.json;

const idx   = $input.itemIndex ?? 0;
const prev  = $('Restore nach Ordneranlage').all();
const found = prev[idx];

if (!found) {
  throw new Error(
    `[MergeWarmup] Kein Item bei Index ${idx} in 'Restore nach Ordneranlage' ` +
    `(${prev.length} Items). batchSize korrekt?`
  );
}
const meta = found.json;

if (!meta.vorgangKey) {
  console.warn('[MergeWarmup] WARNUNG: meta.vorgangKey fehlt.');
}

// Alle Felder aus meta weitergeben (inkl. Force-Refresh-Felder via ...meta)
return [{
  json: {
    ...meta,
    _warmupStatus: warmup.statusCode || '',
    _warmupUrl:    meta.allrisUrl    || meta.sourceUrl || ''
  }
}];

// Stellt alle Vorgang-Metadaten nach den Nextcloud-Folder-Nodes wieder her.
// Bei batchSize:1 gibt es pro Ausführung genau ein Item aus Build Nextcloud Path.
// $input.itemIndex ?? 0 als sicherer Fallback falls der Wert undefined ist.

const idx = $input.itemIndex ?? 0;
const src = $('Build Nextcloud Path').all();

const found = src[idx];
if (!found) {
  throw new Error(
    `[RestoreOrdner] Kein Item bei Index ${idx} in 'Build Nextcloud Path' ` +
    `(${src.length} Items vorhanden). batchSize korrekt auf 1 gesetzt?`
  );
}
const meta = found.json;

if (!meta.vorgangKey) {
  console.warn(`[RestoreOrdner] WARNUNG: kein vorgangKey bei Index ${idx}`);
}

// Alle Felder aus meta weitergeben (inkl. Force-Refresh-Felder)
return [{
  json: {
    ...meta,
    // Sicherstellen dass Pflichtfelder vorhanden
    vorgangKey:    meta.vorgangKey    || '',
    nc_pathYear:   meta.nc_pathYear   || '',
    nc_pathVorg:   meta.nc_pathVorg   || '',
    nc_pathOrig:   meta.nc_pathOrig   || ''
  }
}];

// Prüft den Download. Akzeptiert jetzt PDF, JPG, JPEG, PNG und andere echte Binary-Dateien.
// Läuft im Modus: Run Once for Each Item
// V2: Verifiziert PDF-Dateien zusätzlich per Magic-Byte-Prüfung (%PDF-) und lässt
// unbekannte Dateigrößen nicht mehr automatisch durch, um leere/kaputte Downloads
// zu erkennen, bevor sie als erfolgreich nach Nextcloud hochgeladen werden.

const item = $input.item;
const j = item.json || {};
const binary = item.binary || {};
const bin = binary.data || {};

function parseSize(value) {
  if (typeof value === 'number') return value;

  const s = String(value || '').trim().toLowerCase().replace(',', '.');
  const n = parseFloat(s);

  if (!Number.isFinite(n)) return 0;

  if (s.includes('mb')) return Math.round(n * 1024 * 1024);
  if (s.includes('kb')) return Math.round(n * 1024);

  return Math.round(n);
}

const hasBinary = !!binary.data;

// Tatsächliche Bytes laden, wenn möglich – zuverlässiger als gemeldete Metadaten.
let realBuffer = null;
if (hasBinary) {
  try {
    realBuffer = await this.helpers.getBinaryDataBuffer(0, 'data');
  } catch (e) {
    console.warn(`[Prüfe Download] Konnte Binärdaten nicht laden (${j.vorgangKey || '?'} / ${j.nc_fileName || '?'}): ${e.message}`);
  }
}

const mimeType = String(
  bin.mimeType ||
  bin.mime ||
  j.mimeType ||
  ''
).toLowerCase();

const fileName = String(
  j.nc_fileName ||
  bin.fileName ||
  ''
).toLowerCase();

const fileExtension = String(
  bin.fileExtension ||
  fileName.split('.').pop() ||
  ''
).toLowerCase();

const reportedFileSize = parseSize(
  bin.fileSize ||
  bin.fileSizeBytes ||
  j.fileSize ||
  0
);
const fileSize = realBuffer ? realBuffer.length : reportedFileSize;

const isPdf =
  mimeType.includes('pdf') ||
  fileName.endsWith('.pdf') ||
  fileExtension === 'pdf';

const isImage =
  mimeType.includes('image/jpeg') ||
  mimeType.includes('image/jpg') ||
  mimeType.includes('image/png') ||
  mimeType.includes('image/gif') ||
  fileName.endsWith('.jpg') ||
  fileName.endsWith('.jpeg') ||
  fileName.endsWith('.png') ||
  fileName.endsWith('.gif') ||
  ['jpg', 'jpeg', 'png', 'gif'].includes(fileExtension);

const isOfficeOrOtherAllowed =
  fileName.endsWith('.doc') ||
  fileName.endsWith('.docx') ||
  fileName.endsWith('.xls') ||
  fileName.endsWith('.xlsx') ||
  fileName.endsWith('.ppt') ||
  fileName.endsWith('.pptx') ||
  fileName.endsWith('.odt') ||
  fileName.endsWith('.ods') ||
  fileName.endsWith('.zip') ||
  ['doc', 'docx', 'xls', 'xlsx', 'ppt', 'pptx', 'odt', 'ods', 'zip'].includes(fileExtension);

const isHtml =
  mimeType.includes('text/html') ||
  mimeType.includes('html') ||
  fileName.endsWith('.html') ||
  fileName.endsWith('.htm');

// Magic-Byte-Prüfung: eine als PDF erkannte Datei muss tatsächlich mit %PDF- beginnen.
// Fängt mislabelte oder kaputte Downloads ab, die Metadaten/Endung nicht verraten.
let magicBytesOk = true;
if (isPdf && realBuffer) {
  const header = realBuffer.subarray(0, 5).toString('latin1');
  magicBytesOk = header === '%PDF-';
  if (!magicBytesOk) {
    console.warn(`[Prüfe Download] Magic-Byte-Check fehlgeschlagen (${j.vorgangKey || '?'} / ${j.nc_fileName || '?'}): erwartet %PDF-, erhalten ${header}`);
  }
}

// Keine Freikarte mehr für unbekannte Größe: eine Datei mit fileSize=0 ist verdächtig,
// nicht automatisch gültig. Für PDFs gilt eine höhere Mindestgröße, weil selbst ein
// einzelnes Deckblatt praktisch nie kleiner als ein paar hundert Byte ist.
const minSize = isPdf ? 800 : 300;
const sizeOk = fileSize > minSize;

const downloadOk =
  hasBinary &&
  sizeOk &&
  !isHtml &&
  magicBytesOk &&
  (
    isPdf ||
    isImage ||
    isOfficeOrOtherAllowed ||
    fileSize > 2000
  );

if (!downloadOk) {
  console.warn(
    `[Prüfe Download] FEHLER: ${j.vorgangKey || '?'} / ${j.nc_fileName || '?'} ` +
    `mime=${mimeType}, ext=${fileExtension}, size=${fileSize}, hasBinary=${hasBinary}, magicBytesOk=${magicBytesOk}`
  );
}

return {
  json: {
    ...j,
    downloadOk,
    _downloadOk: downloadOk,
    _downloadMimeType: mimeType,
    _downloadFileName: fileName,
    _downloadFileExtension: fileExtension,
    _downloadFileSize: fileSize,
    _downloadHasBinary: hasBinary,
    _downloadMagicBytesOk: magicBytesOk,
    _downloadRejectedReason: downloadOk
      ? ''
      : `Nicht akzeptiert: mime=${mimeType}, ext=${fileExtension}, size=${fileSize}, hasBinary=${hasBinary}, magicBytesOk=${magicBytesOk}`
  },
  binary
};

// ── pairedItem-Index sicher extrahieren ──────────────────────────────────────
// n8n liefert pairedItem in verschiedenen Formen je nach Version:
//   - Zahl:               pairedItem = 0
//   - Objekt mit .item:   pairedItem = { item: 0 }
//   - Array:              pairedItem = [{ item: 0 }]
//   - undefined:          nicht gesetzt (ältere n8n-Versionen)
function getPairedIndex(pairedItem) {
  if (pairedItem === undefined || pairedItem === null) return null;
  if (typeof pairedItem === 'number')                  return pairedItem;
  if (Array.isArray(pairedItem) && pairedItem.length)  return pairedItem[0]?.item ?? pairedItem[0] ?? null;
  if (typeof pairedItem === 'object')                  return pairedItem.item ?? null;
  return null;
}

// ── Markiere Upload Erfolg ───────────────────────────────────────────────────
// Kommt vom SUCCESS-Ausgang (out0) des Nextcloud-Upload-Nodes.
//
// Metadaten-Strategie (in Priorität):
//   1. item.json vollständig → direkt nutzen
//   2. pairedItem → Index in $('Upload Kontext sichern').all()
//      pairedItem zeigt auf das Item das in den NC-Upload hineinging,
//      also den Output von 'Upload Kontext sichern' – kein Index-Drift
//   3. docRunKey-Suche in $('Upload Kontext sichern').all() (falls j.docRunKey vorhanden)
//   4. Kein src[0]-Fallback – stattdessen Fehler mit _uploadOk: false

const item = $input.item;
