      nc_pathOrig:   j.nc_pathOrig   || '',
      nc_fileName:   j.nc_fileName   || '',
      nc_docIndex:   j.nc_docIndex   ?? -1,
      docRunKey:     j.docRunKey     || '',
      _uploadOk:     false,
      _uploadError:  errMsg
    }
  }];
}

console.log(`[UploadErfolg] ✓ ${meta.nc_fileName} – ${meta.vorgangKey} [via ${source}]`);

return {
  json: {
    vorgangKey:     meta.vorgangKey,
    volfdnr:        meta.volfdnr        || '',
    title:          meta.title          || '',
    vorgangsnummer: meta.vorgangsnummer || '',
    allrisUrl:      meta.allrisUrl      || '',
    sourceUrl:      meta.sourceUrl      || '',
    documentCount:  meta.documentCount  || 0,
    documentsJson:  meta.documentsJson  || '[]',
