// ── Markiere Upload Fehler ───────────────────────────────────────────────────
// Kommt vom:
//   a) false-Ausgang von 'IF Download OK?'
//      → item.json ist vollständig (direkt aus Prüfe Download, kein NC-Upload)
//   b) ERROR-Ausgang (out1) von 'Upload Original to Nextcloud'
//      → NC-Node kann JSON ersetzen → pairedItem nötig
//
// Metadaten-Strategie:
//   1. item.json vollständig → direkt nutzen
//   2. pairedItem → Index in $('Upload Kontext sichern').all()
//   3. docRunKey-Suche in $('Upload Kontext sichern').all()
//   4. Kein src[0]-Fallback – expliziter Fehler

const item = $input.item;
const j    = item.json;

const REQUIRED = ['vorgangKey','documentCount','nc_pathVorg','nc_pathOrig',
                  'nc_fileName','nc_docIndex','docRunKey'];
const hasFullMeta = REQUIRED.every(f => j[f] !== undefined && j[f] !== '' && j[f] !== null);

let meta   = null;
let source = '';

// ── Priorität 1: item.json vollständig ───────────────────────────────────────
// Gilt immer für Fall a (Download-Fehler-Branch – NC-Node nie durchlaufen)
if (hasFullMeta) {
  meta   = j;
  source = 'item.json direkt';
  console.log(`[UploadFehler] P1 – Metadaten direkt: ${j.docRunKey}`);
}

// ── Priorität 2: pairedItem → Upload Kontext sichern ─────────────────────────
