      nc_fileName:   j.nc_fileName   || '',
      nc_docIndex:   j.nc_docIndex   ?? -1,
      docRunKey:     j.docRunKey     || '',
      _uploadOk:     false,
      _uploadError:  errMsg
    }
  }];
}

// ── Fehlerursache bestimmen ───────────────────────────────────────────────────
// Fall a: _downloadOk ist false (aus Prüfe Download)
// Fall b: _downloadOk ist true, aber NC-Upload fehlgeschlagen
const downloadFailed = meta._downloadOk === false || j._downloadOk === false;
const uploadErrMsg   =
  item.error?.message ||
  j.error?.message    ||
  j.message           || '';

const uploadError = downloadFailed
  ? `Download fehlgeschlagen: ${meta._downloadError || j._downloadError || 'unbekannt'}`
  : `Upload fehlgeschlagen: ${uploadErrMsg || 'Nextcloud-Fehler (kein Detail)'}`;

console.warn(`[UploadFehler] ✗ ${meta.nc_fileName} – ${meta.vorgangKey}: ${uploadError} [via ${source}]`);

return {
  json: {
    vorgangKey:     meta.vorgangKey,
    volfdnr:        meta.volfdnr        || '',
    title:          meta.title          || '',
    vorgangsnummer: meta.vorgangsnummer || '',
    allrisUrl:      meta.allrisUrl      || '',
    sourceUrl:      meta.sourceUrl      || '',
    documentCount:  meta.documentCount  || 0,
    documentsJson:  meta.documentsJson  || '[]',
    nc_pathYear:    meta.nc_pathYear    || '',
    nc_pathVorg:    meta.nc_pathVorg    || '',
    nc_pathOrig:    meta.nc_pathOrig    || '',
    nc_folder:      meta.nc_folder      || '',
    nc_fileName:    meta.nc_fileName    || '',
    nc_docIndex:    meta.nc_docIndex    ?? 0,
    docRunKey:      meta.docRunKey      || '',
    firstseen:      meta.firstseen      || '',
    _uploadOk:      false,
    _uploadError:   uploadError
  }
};

// Sichert alle Metadaten unmittelbar vor dem Nextcloud-Upload.
