};

// ═══════════════════════════════════════════════════════════════════
// ARCHIV KONFIGURATION – hier Schalter für Force-Refresh setzen
// ═══════════════════════════════════════════════════════════════════
//
// forceRefreshDocuments:
//   false (Standard) → Normalbetrieb: nur Vorgänge ohne nextcloudFolder
//   true             → Erzwingt erneute Verarbeitung bereits archivierter Vorgänge
//
// forceRefreshOnlyVorgangKey:
//   ""               → Alle passenden Vorgänge (nur wenn forceRefreshAllConfirmed: true)
//   "2026_193"       → Nur diesen einen Vorgang erneuern
//
// forceRefreshAllConfirmed:
//   false (Standard) → Sicherheitsbremse: verhindert versehentliches Neuarchivieren aller Vorgänge
//   true             → Alle archivierten Vorgänge erneut verarbeiten (nur mit forceRefreshDocuments: true)
//
// deleteExistingBeforeUpload:
//   true             → Versucht bestehende Datei in Nextcloud vor Upload zu löschen
//   false            → Überschreibt direkt (falls Nextcloud-Node das unterstützt)

return [{
  json: {
    forceRefreshDocuments:       false,
    forceRefreshOnlyVorgangKey:  "",
    forceRefreshAllConfirmed:    false,
