// Stellt nach dem Nextcloud-Lösch-Node die ursprünglichen Upload-Metadaten
// und das Binary aus "Upload Kontext sichern" wieder her.
// Wichtig: Der Lösch-Node gibt oft keine brauchbaren JSON-Daten/Binary weiter.

const inputItems = $input.all();
const ctxItems = $('Upload Kontext sichern').all();

if (!ctxItems || ctxItems.length === 0) {
  throw new Error('[Restore nach Löschung] Keine Items aus "Upload Kontext sichern" gefunden.');
}

const out = [];

for (let i = 0; i < inputItems.length; i++) {
  const incoming = inputItems[i] || {};
  const incomingJson = incoming.json || {};

  // 1. bevorzugt gleicher Index
  let ctx = ctxItems[i];

  // 2. fallback per docRunKey, falls vorhanden
  const key =
    incomingJson.docRunKey ||
    incomingJson._uploadContextDocRunKey ||
    '';

  if ((!ctx || !ctx.json?.vorgangKey) && key) {
    ctx = ctxItems.find(x => x.json?.docRunKey === key);
  }

  // 3. letzter Fallback bei batchSize/Branch-Problemen
  if (!ctx || !ctx.json?.vorgangKey) {
    ctx = ctxItems[0];
  }

  if (!ctx || !ctx.json || !ctx.json.vorgangKey) {
    throw new Error(
      `[Restore nach Löschung] Upload-Kontext nicht rekonstruierbar. index=${i}, ctxItems=${ctxItems.length}`
    );
  }

  if (!ctx.binary || !ctx.binary.data) {
    throw new Error(
      `[Restore nach Löschung] Binary "data" fehlt im Upload-Kontext für ${ctx.json.vorgangKey} / ${ctx.json.nc_fileName || '?'}`
    );
  }

  out.push({
    json: {
      ...ctx.json,

      // Diagnosefelder
      _deleteNodeHadError: !!incomingJson.error,
      _deleteNodeError: incomingJson.error || '',
      _restoreNachLoeschungOk: true,
      _restoreNachLoeschungSource: ctxItems[i] ? `Upload Kontext sichern[${i}]` : 'Upload Kontext sichern[0]'
    },
    binary: ctx.binary
  });
}

return out;

// Baut einen deterministischen, eindeutigen Titel als Paperless-Dubletten-Schlüssel
// und löst Tag/Correspondent/DocumentType-IDs auf (angelegt durch die Paperless-
// Taxonomie-Kette am Workflow-Anfang, siehe 'Paperless Normalize ...'-Nodes).
// Schema: <vorgangKey>_<nc_fileName>, bereinigt (kein '/', keine Mehrfach-Unterstriche).

const j = $input.item.json;

function sanitize(str, maxLen) {
  return String(str || '')
    .replace(/[\/\\:*?"<>|\r\n]/g, '_')
    .replace(/\s+/g, '_')
    .replace(/_+/g, '_')
    .replace(/^_+|_+$/g, '')
    .substring(0, maxLen || 150);
}

