  documentTypeId = $('Paperless Normalize DocType Anlage').first()?.json?.id || null;
} else {
  documentTypeId = $('Paperless Normalize DocType Dokument').first()?.json?.id || null;
}

const paperlessMetaOk = !!(tagId && correspondentId && documentTypeId);
