} else if (j.id !== undefined) {
  id = j.id;
}
if (!id) {
  console.warn('[Paperless] DocumentType "Dokument": konnte keine ID ermitteln (weder gefunden noch angelegt).');
}
return { json: { id, name: 'Dokument' } };

const inputItems = $input.all();
const warmupItems = $('HTTP Vorgangsseite Warmup').all();

const out = [];

const ALLOWED_FILE_EXTENSIONS = [
  'pdf',
  'jpg',
  'jpeg',
  'png',
  'gif',
  'tif',
  'tiff',
  'doc',
  'docx',
  'xls',
  'xlsx',
  'ppt',
  'pptx',
  'odt',
  'ods',
  'zip'
];

function cleanText(html) {
  return String(html || '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\s+/g, ' ')
    .trim();
}

function getExtension(url) {
  const clean = String(url || '').split('?')[0].split('#')[0];
  const m = clean.match(/\.([a-zA-Z0-9]{2,6})$/);
  if (!m) return '';
  const ext = m[1].toLowerCase();
  return ALLOWED_FILE_EXTENSIONS.includes(ext) ? ext : '';
}

function resolveUrl(rawHref, baseUrl) {
  const href = String(rawHref || '').replace(/&amp;/g, '&').trim();

  try {
    return href.startsWith('http')
      ? href
      : new URL(href, baseUrl).href;
  } catch (e) {
    if (href.startsWith('/')) {
      return 'https://www.goslar.de' + href;
    }
    return 'https://www.goslar.de/stadt/politik/allris/' + href;
  }
}

function isRealDocumentLink(url) {
  const u = String(url || '').toLowerCase();
  const ext = getExtension(u);

  if (!u) return false;

  if (u.includes('/stadt/politik/allris/do027.asp')) return true;
  if (u.includes('dolfdnr=')) return true;

  if (u.includes('/stadt/politik/allris/___tmp/tmp/')) return true;
  if (u.includes('/allris/___tmp/tmp/')) return true;

  if (ext) return true;

  return false;
}

function classifyDocument(url, label, surroundingHtml) {
  const u = String(url || '').toLowerCase();
  const l = String(label || '').toLowerCase();
  const ctx = cleanText(surroundingHtml || '').toLowerCase();

  const isAnlage =
    ctx.includes('anlagen') ||
    ctx.includes('anlage') ||
    l.includes('anlage') ||
    l.includes('anlagen') ||
    u.includes('/anlagen/') ||
    u.includes('-anlagen/');

  const isVorlage =
    ctx.includes('dokumente') ||
    ctx.includes('vorlage') ||
    l.includes('vorlage') ||
    u.includes('vorlage');

  if (isAnlage) return 'anlage';
  if (isVorlage) return 'original';
  return 'document';
}

function buildDocKey(url, type, label) {
  const dol = String(url || '').match(/DOLFDNR=(\d+)/i)?.[1];
  if (dol) return `dol_${dol}`;

  let fileName = '';
  try {
    const parsed = new URL(url);
    fileName = decodeURIComponent(parsed.pathname.split('/').pop() || '');
  } catch (e) {
    fileName = String(url || '').split('/').pop() || '';
  }

  fileName = fileName
    .split('?')[0]
    .split('#')[0]
    .replace(/[^a-zA-Z0-9._-]/g, '_')
    .replace(/_+/g, '_')
    .replace(/^_+|_+$/g, '')
    .substring(0, 120);

  if (fileName) return `${type}_${fileName}`;

  const fallback = cleanText(label || '')
    .replace(/[^a-zA-Z0-9._-]/g, '_')
    .replace(/_+/g, '_')
    .replace(/^_+|_+$/g, '')
    .substring(0, 80);

  return fallback ? `${type}_${fallback}` : `${type}_unknown`;
}

for (let i = 0; i < inputItems.length; i++) {
  const meta = inputItems[i].json || {};
  const warmup = warmupItems[i]?.json || warmupItems[0]?.json || {};

  const html =
    warmup.html ||
    warmup.data ||
    warmup.body ||
    meta.html ||
    '';

  const baseUrl =
    meta.allrisUrl ||
    meta.sourceUrl ||
    'https://www.goslar.de/stadt/politik/allris/vo040_r.asp';

  const matches = [...String(html || '').matchAll(/<a\b[^>]*href=["']([^"']+)["'][^>]*>([\s\S]*?)<\/a>/gi)];

  const found = [];
  const seen = new Set();

  for (const match of matches) {
    const rawHref = match[1] || '';
    const rawLabel = match[2] || '';
    const label = cleanText(rawLabel);

    if (!rawHref) continue;

    const hrefLower = rawHref.toLowerCase();

    if (
      hrefLower.startsWith('#') ||
      hrefLower.startsWith('javascript:') ||
      hrefLower.startsWith('mailto:') ||
      hrefLower.startsWith('tel:')
    ) {
      continue;
    }

    const link = resolveUrl(rawHref, baseUrl);
    const urlLower = link.toLowerCase();

    if (urlLower.includes('vo020_r.asp?volfdnr=')) continue;
    if (urlLower.includes('vo040_r.asp')) continue;

    if (!isRealDocumentLink(link)) continue;
    if (seen.has(link)) continue;
    seen.add(link);

    const start = Math.max(0, match.index - 500);
    const end = Math.min(String(html).length, match.index + match[0].length + 500);
    const surroundingHtml = String(html).slice(start, end);

    const type = classifyDocument(link, label, surroundingHtml);
    const docKey = buildDocKey(link, type, label);

    found.push({
      url: link,
      type,
      label,
      docKey
    });
  }

  if (found.length > 0) {
    console.log(
      `[Aktualisiere Dokumentlinks] ${meta.vorgangKey}: ` +
      `${found.length} frische Dokumentlinks aus Warmup-Seite gefunden.`
    );

    out.push({
      json: {
        ...meta,
        documentsJson: JSON.stringify(found),
        documentCount: found.length,
        _documentsRefreshedFromWarmup: true,
        _documentsRefreshCount: found.length
      }
    });
  } else {
    console.warn(
      `[Aktualisiere Dokumentlinks] ${meta.vorgangKey}: Keine frischen Dokumentlinks gefunden. Verwende alte documentsJson.`
    );

    out.push({
      json: {
        ...meta,
        _documentsRefreshedFromWarmup: false,
        _documentsRefreshCount: 0
      }
    });
  }
}

return out;
